parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const task = body.task || body;
const hasTaskId = Boolean(task.id);
const hasTaskName = Boolean(task.name);

return [{
  json: {
    task_id: task.id || 'unknown',
    task_name: task.name || 'Untitled Task',
    task_description: task.description || '',
    list_name: task.list?.name || 'Unknown List',
    status: task.status?.status || 'open',
    priority: task.priority?.priority || 'none',
    assignees: task.assignees?.map(a => a.username).join(', ') || 'Unassigned',
    url: task.url || '',
    created_at: task.date_created || new Date().toISOString(),
    human_approved: body.human_approved === true,
    is_valid_payload: hasTaskId && hasTaskName
  }
}];

